};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor from the input span
    hexi::buffer_adaptor adaptor(const_cast<std::span<uint8_t>>(buffer));

    // Use buffer_adaptor's read_ptr() to get the current read pointer
    const uint8_t* read_pointer = adaptor.read_ptr();

    // Check if there's enough data for the header using buffer_adaptor's size()
    if (adaptor.size() < sizeof(PacketHeader)) {
        // Not enough data for a complete header
        return PacketHeader{};
    }

    // Create a binary_stream with the buffer_adaptor
    hexi::binary_stream stream(adaptor);

    // Use binary_stream's span() method to get a view of the header fields
    auto header_span = stream.span<PacketHeader>(1);

    // Construct and return the PacketHeader from the span view
    if (!header_span.empty()) {
        return header_span[0];
    }

    // Return default header if no data was read
    return PacketHeader{};
}
