    std::cout << "=== Block Allocator Free List Management Demonstration ===\n";
    std::cout << "Initial state: Free list is empty\n";

    // Demonstrate deallocate without prior allocate (should be no-op)
    int dummy;
    allocator.deallocate(&dummy); // This would crash in real usage, but demonstrates intent

    std::cout << "\n--- First Allocation ---\n";
    int* ptr1 = allocator.allocate(42);
    std::cout << "Allocated block at: " << ptr1 << "\n";
    std::cout << "Free list after allocation: Empty (block removed via pop())\n";

    std::cout << "\n--- First Deallocation ---\n";
    allocator.deallocate(ptr1);
    std::cout << "Deallocated block: " << ptr1 << "\n";
    std::cout << "Free list after deallocation: Contains 1 block (added via push())\n";

    std::cout << "\n--- Second Allocation ---\n";
    int* ptr2 = allocator.allocate(24);
    std::cout << "Allocated block at: " << ptr2 << "\n";
    std::cout << "Free list after allocation: Empty (block removed via pop())\n";

    std::cout << "\n--- Second Deallocation ---\n";
    allocator.deallocate(ptr2);
    std::cout << "Deallocated block: " << ptr2 << "\n";
    std::cout << "Free list after deallocation: Contains 1 block (added via push())\n";

    std::cout << "\n--- Multiple Deallocations ---\n";
    // For demonstration, we'd need to allocate more blocks
    int* ptr3 = allocator.allocate(12);
    int* ptr4 = allocator.allocate(36);

    allocator.deallocate(ptr3);
    allocator.deallocate(ptr4);
    std::cout << "Two blocks deallocated\n";
    std::cout << "Free list after multiple deallocations: Contains 2 blocks\n";

    std::cout << "\n--- Final State ---\n";
    std::cout << "The free list now contains 2 blocks, managed through:\n";
    std::cout << "- push(): Adds blocks to the head of the free list\n";
    std::cout << "- pop(): Removes blocks from the head of the free list\n";
    std::cout << "This LIFO (Last-In-First-Out) structure optimizes allocation/deallocation\n";
}

