std::vector<uint8_t> read_file_data(const std::filesystem::path& file_path, size_t bytes_to_read) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Ensure we don't read more than available data
    size_t bytes_to_read_clamped = std::min(bytes_to_read, buffer.size());
    if (bytes_to_read_clamped == 0) {
        return {};
    }

    std::vector<uint8_t> data(bytes_to_read_clamped);
    buffer.read(data.data(), bytes_to_read_clamped);
    return data;
}

std::vector<uint8_t> preview_file_data(const std::filesystem::path& file_path, size_t bytes_to_preview) {
    hexi::file_buffer buffer(file_path);
    if (!buffer) {
        return {}; // Return empty vector if file cannot be opened
    }

    // Ensure we don't preview more than available data
    size_t bytes_to_preview_clamped = std::min(bytes_to_preview, buffer.size());
    if (bytes_to_preview_clamped == 0) {
        return {};
    }

    std::vector<uint8_t> data(bytes_to_preview_clamped);
    buffer.copy(data.data(), bytes_to_preview_clamped);
    return data;
}

