#include <hexi/pmc/buffer_read_adaptor.h>
#include <hexi/pmc/buffer_write_adaptor.h>
#include <vector>
#include <cstdint>
#include <cassert>

std::vector<uint8_t> write_and_read_data(const std::vector<uint8_t>& input_data) {
    // Create a buffer to hold the data
    std::vector<uint8_t> buffer;

    // Create buffer_write_adaptor instance
    hexi::pmc::buffer_write_adaptor<std::vector<uint8_t>> write_adaptor(buffer);

    // Check available space using free() before writing
    if (write_adaptor.free() < input_data.size()) {
        // Resize buffer if needed to accommodate the data
        buffer.resize(input_data.size());
    }

    // Use write() method to write data to the buffer
    write_adaptor.write(input_data.data(), input_data.size());

    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<std::vector<uint8_t>> read_adaptor(buffer);

    // Check available data using size() before reading
    assert(read_adaptor.size() >= input_data.size());

    // Use read() method to read data back from the buffer
    std::vector<uint8_t> output_data(input_data.size());
    read_adaptor.read(output_data.data(), input_data.size());

    return output_data;
}

std::vector<uint8_t> peek_data_without_advancing(const std::vector<uint8_t>& buffer_data, std::size_t peek_size) {
    // Create buffer_read_adaptor instance
    hexi::pmc::buffer_read_adaptor<const std::vector<uint8_t>> read_adaptor(buffer_data);

    // Check if we have enough data to peek
    if (peek_size > read_adaptor.size()) {
        peek_size = read_adaptor.size(); // Peek only available data
    }

    // Use copy() method to peek at data without advancing the read pointer
    std::vector<uint8_t> peek_buffer(peek_size);
    read_adaptor.copy(peek_buffer.data(), peek_size);

    // Use read_ptr() to get a pointer to the current read position
    const uint8_t* current_read_ptr = read_adaptor.read_ptr();

    // Use read() to actually consume the data (advance the read pointer)
    std::vector<uint8_t> consumed_data(peek_size);
    read_adaptor.read(consumed_data.data(), peek_size);

    return peek_buffer; // Return the peeked data
}
